pool = AMMPool(1000, 2_000_000)
trade_sizes = [1, 5, 10, 25, 50]
results = []
for size in trade_sizes:
    amount_out, impact = pool.swap_exact_input(size, is_eth_input=True)
    results.append({
        'eth_in': size,
        'usdc_out': amount_out,
        'price_impact': impact,
        'pool_price': pool.current_price()
    })
    if abs(impact) > 0.01:
        print(f'Trade {size} ETH exceeds 1% slippage at {impact*100:.2f}%')
